const BREAKPOINTS: Array<{ query: string; hiddenClass: string }> = [
  { query: '(min-width: 1200px)', hiddenClass: 'hidden-5kc8ar' },
  { query: '(min-width: 810px) and (max-width: 1199.98px)', hiddenClass: 'hidden-f6240l' },
  { query: '(max-width: 809.98px)', hiddenClass: 'hidden-4b7nwy' },
];

export default function Footer() {
  // All three breakpoint copies (Desktop v-1ldiete / Tablet v-e5cvdt /
  // Phone v-1sin03z) ship in the markup inside .ssr-variant wrappers.
  const ref = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const root = ref.current;
    if (!root) return;
    const copies = [...root.querySelectorAll<HTMLElement>('.ssr-variant')].map((el) => {
      const placeholder = document.createComment('ssr-variant');
      return { el, placeholder, mounted: true };
    });
    const mqls = BREAKPOINTS.map((b) => window.matchMedia(b.query));
    const apply = () => {
      const active = BREAKPOINTS.find((_, i) => mqls[i].matches) ?? BREAKPOINTS[0];
      for (const c of copies) {
        const keep = !c.el.classList.contains(active.hiddenClass);
        if (keep && !c.mounted) {
          c.placeholder.replaceWith(c.el);
          c.mounted = true;
        } else if (!keep && c.mounted) {
          c.el.replaceWith(c.placeholder);
          c.mounted = false;
        }
      }
    };
    apply();
    mqls.forEach((m) => m.addEventListener('change', apply));
    return () => {
      mqls.forEach((m) => m.removeEventListener('change', apply));
      // restore all copies so a re-mount starts from the full markup
      copies.forEach((c) => {
        if (!c.mounted) c.placeholder.replaceWith(c.el);
      });
    };
  }, []);

  return <div ref={ref} className="framer-yshUJ site-footer" dangerouslySetInnerHTML={{ __html: FOOTER_HTML }} />;
}
